'use strict';

// MODULES //

var stride2offset = require( '@stdlib/strided/base/stride2offset' );
var ndarray = require( './ndarray.js' );


// MAIN //

/**
* Computes the minimum value of a strided array according to a mask, ignoring `NaN` values.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {NumericArray} x - input array
* @param {integer} strideX - `x` stride length
* @param {NumericArray} mask - mask array
* @param {integer} strideMask - `mask` stride length
* @returns {number} minimum value
*
* @example
* var x = [ 1.0, -2.0, -4.0, 2.0, NaN ];
* var mask = [ 0, 0, 1, 0, 0 ];
*
* var v = nanmskmin( x.length, x, 1, mask, 1 );
* // returns -2.0
*/
function nanmskmin(N, x, strideX, offsetX, mask, strideMask, offsetMask) {
    var min;
    var ix;
    var im;
    var v;
    var i;

    if (N <= 0) {
        return NaN;
    }

    // Convert to accessor-aware object
    var ox = arraylike2object(x);
    var om = arraylike2object(mask);

    // Use accessor function if needed
    if (ox.accessorProtocol || om.accessorProtocol) {
        return accessors(N, ox, strideX, offsetX, om, strideMask, offsetMask);
    }

    ix = offsetX;
    im = offsetMask;

    for (i = 0; i < N; i++) {
        v = ox.data[ix];
        if (v === v && om.data[im] === 0) {
            break;
        }
        ix += strideX;
        im += strideMask;
    }
    if (i === N) {
        return NaN;
    }
    min = v;
    i += 1;

    for (; i < N; i++) {
        ix += strideX;
        im += strideMask;
        if (om.data[im]) {
            continue;
        }
        v = ox.data[ix];
        if (isnan(v)) {
            continue;
        }
        if (v < min || (v === min && isNegativeZero(v))) {
            min = v;
        }
    }
    return min;
}


// EXPORTS //

module.exports = nanmskmin;
